import * as fs from 'fs';
import * as path from 'path';
import * as crypto from 'crypto';
import EXIFParser from 'exif-parser';

const BASE_DIR = path.resolve('uploads/photos');

async function processPhotos() {
    const filesWithExifCount = { count: 0 };
    const duplicatePairsCount = { count: 0 };
    const renamedFilesCount = { count: 0 };
    const folderDistribution: Record<string, number> = {};

    // Get all files from existing subfolders (to reconstruct state)
    const subfolders = ['2023', '2024', 'unknown'];
    const allFiles: string[] = [];

    for (const folder of subfolders) {
        const folderPath = path.join(BASE_DIR, folder);
        if (fs.existsSync(folderPath)) {
            const files = fs.readdirSync(folderPath);
            for (const file of files) {
                allFiles.push(path.join(folderPath, file));
            }
        }
    }

    const fileHashes: Record<string, string[]> = {};

    for (const filePath of allFiles) {
        const buffer = fs.readFileSync(filePath);
        const md5 = crypto.createHash('md5').update(buffer).digest('hex');

        if (!fileHashes[md5]) {
            fileHashes[md5] = [];
        }
        fileHashes[md5].push(filePath);

        // Check EXIF
        let exifDate: Date | null = null;
        try {
            const parser = EXIFParser.create(buffer);
            const result = parser.parse();
            if (result.tags.DateTimeOriginal) {
                exifDate = new Date(result.tags.DateTimeOriginal * 1000);
            }
        } catch (e) {
            // No EXIF or error parsing
        }

        const parentFolder = path.basename(path.dirname(filePath));
        if (parentFolder !== 'unknown') {
            filesWithExifCount.count++;
            renamedFilesCount.count++;
            folderDistribution[parentFolder] = (folderDistribution[parentFolder] || 0) + 1;
        } else {
            folderDistribution['unknown'] = (folderDistribution['unknown'] || 0) + 1;
        }
    }

    // Count duplicate pairs
    for (const md5 in fileHashes) {
        if (fileHashes[md5].length > 1) {
            duplicatePairsCount.count += (fileHashes[md5].length - 1);
        }
    }

    console.log(`FilesWithEXIF: ${filesWithExifCount.count}`);
    console.log(`DuplicatePairs: ${duplicatePairsCount.count}`);
    console.log(`FilesRenamed: ${renamedFilesCount.count}`);
    console.log(`FolderDistribution: ${JSON.stringify(folderDistribution)}`);
}

processPhotos().catch(console.error);

